const item = $input.first().json;
const headers = {};
for (const [key, value] of Object.entries(item.headers || {})) {
  headers[key.toLowerCase()] = Array.isArray(value) ? String(value[0] || '') : String(value || '');
}
const expectedToken = $env.DBA_WEBHOOK_TOKEN || '';
const providedToken = headers['x-dba-token'] || '';
const body = item.body && typeof item.body === 'object' ? item.body : item;
const params = body.params && typeof body.params === 'object' ? body.params : {};
const action = String(body.action || '').trim();
const db = String(body.db || '').trim();
const alertId = String(body.alert_id || params.alert_id || '').trim();
const tablespace = String(params.tablespace || params.selected_tablespace || body.tablespace || '').trim().toUpperCase();
function sqlString(value, max = 4000) {
  return String(value || '').slice(0, max).replace(/'/g, "''");
}
const authorized = !expectedToken || providedToken === expectedToken;
const metadataSql = `SELECT
  df.tablespace_name,
  df.file_name,
  ROUND(df.bytes / 1024 / 1024 / 1024, 2) AS file_size_gb,
  df.autoextensible,
  ROUND(df.maxbytes / 1024 / 1024 / 1024, 2) AS max_size_gb,
  ROUND(NVL(fs.free_bytes, 0) / 1024 / 1024 / 1024, 2) AS free_gb,
  p.value AS db_create_file_dest
FROM dba_data_files df
LEFT JOIN (
  SELECT file_id, SUM(bytes) free_bytes
  FROM dba_free_space
  GROUP BY file_id
) fs ON fs.file_id = df.file_id
LEFT JOIN v$parameter p ON p.name = 'db_create_file_dest'
WHERE df.tablespace_name = '${sqlString(tablespace, 128)}'
ORDER BY df.bytes DESC`;
return [{ json: { authorized, action, db, alert_id: alertId, correlation_id: body.correlation_id || alertId, requested_by: body.requested_by || 'n8n', user_id: body.user_id, environment: body.environment, os: body.os, db_type: body.db_type, params, tablespace, sql: body.sql || params.sql || '', metadata_sql: metadataSql, received_at: new Date().toISOString() } }];

const req = $('Validate DBA Command').first().json;
const rows = $input.all().map((item) => item.json);
function pick(row, ...keys) {
  for (const key of keys) {
    if (row[key] != null && row[key] !== '') return row[key];
    const upper = key.toUpperCase();
    const lower = key.toLowerCase();
    if (row[upper] != null && row[upper] !== '') return row[upper];
    if (row[lower] != null && row[lower] !== '') return row[lower];
  }
  return undefined;
}
function sanitizeId(value) {
  const text = String(value || '').trim().toUpperCase();
  if (!/^[A-Z][A-Z0-9_$#]{0,127}$/.test(text)) throw new Error(`Invalid tablespace name: ${text}`);
  return text;
}
function dirname(fileName) {
  const normalized = String(fileName || '').replace(/\\/g, '/');
  const idx = normalized.lastIndexOf('/');
  return idx >= 0 ? normalized.slice(0, idx + 1) : '';
}
const tablespace = sanitizeId(req.tablespace);
const sizeGb = Math.max(1, Number(req.params.selected_size_gb || req.params.size_gb || req.params.extend_size_gb || 10));
const largest = rows[0] || {};
const dbCreateFileDest = String(pick(largest, 'db_create_file_dest') || '').trim();
const firstFile = String(pick(largest, 'file_name') || '').trim();
let generatedSql;
if (dbCreateFileDest || firstFile.startsWith('+')) {
  generatedSql = `ALTER TABLESPACE ${tablespace} ADD DATAFILE SIZE ${sizeGb}G AUTOEXTEND ON NEXT 1G MAXSIZE 32G`;
} else {
  const dir = dirname(firstFile);
  if (!dir) throw new Error(`Cannot derive datafile directory for ${tablespace}. Enable OMF or provide an existing datafile path.`);
  const stableSuffix = String(req.alert_id || 'ext').replace(/[^a-zA-Z0-9]/g, '').toLowerCase();
  const filePath = `${dir}${tablespace.toLowerCase()}_auto_${stableSuffix}.dbf`;
  generatedSql = `ALTER TABLESPACE ${tablespace} ADD DATAFILE '${filePath}' SIZE ${sizeGb}G AUTOEXTEND ON NEXT 1G MAXSIZE 32G`;
}
const warnings = [
  'Confirm ASM or filesystem free space before execution.',
  `${req.environment || 'Target'} database storage allocation will change if this SQL is approved.`
];
const explanation = `Tablespace ${tablespace} was approved for extension. The proposal adds ${sizeGb} GB with autoextend enabled, using deterministic SQL generation from current DBA_DATA_FILES metadata.`;
return [{ json: { sql_approval_payload: { alert_id: req.alert_id, correlation_id: req.correlation_id, db: req.db, tablespace, generated_sql: generatedSql, explanation, warnings, database_info: { environment: req.environment, os: req.os, db_type: req.db_type, tablespace, requested_by: req.requested_by, file_count: rows.length, db_create_file_dest: dbCreateFileDest || null, largest_file: firstFile || null, metadata_rows: rows } } } }];

const req = $json;
const rawSql = String(req.sql || '').trim();
const upper = rawSql.replace(/\s+/g, ' ').toUpperCase();
const blocked = ['DROP','TRUNCATE','DELETE','UPDATE','INSERT','MERGE','CREATE USER','GRANT','REVOKE','ALTER SYSTEM','ALTER USER','EXEC','EXECUTE','BEGIN','DECLARE','DBMS_'];
let error = '';
if (!rawSql) error = 'SQL command is required.';
if (!error && rawSql.includes(';')) error = 'Only one SQL statement is allowed. Remove semicolons.';
if (!error) {
  const token = blocked.find((item) => upper.includes(item));
  if (token) error = `SQL contains blocked token: ${token}`;
}
const allowed = /^ALTER\s+TABLESPACE\s+[A-Z0-9_$#"]+\s+ADD\s+DATAFILE\s+/i.test(rawSql) || /^ALTER\s+DATABASE\s+DATAFILE\s+.+\s+RESIZE\s+\d+\s*[KMGT]?B?$/i.test(rawSql) || /^ALTER\s+DATABASE\s+DATAFILE\s+.+\s+AUTOEXTEND\s+ON\s+/i.test(rawSql);
if (!error && !allowed) error = 'SQL is not in the approved tablespace-extension allowlist.';
const tablespace = String(req.params.tablespace || req.tablespace || '').trim().toUpperCase();
const postUsageSql = tablespace ? `WITH datafiles AS (SELECT tablespace_name, SUM(bytes) bytes FROM dba_data_files WHERE tablespace_name = '${tablespace.replace(/'/g, "''")}' GROUP BY tablespace_name), free_space AS (SELECT tablespace_name, SUM(bytes) bytes FROM dba_free_space WHERE tablespace_name = '${tablespace.replace(/'/g, "''")}' GROUP BY tablespace_name) SELECT d.tablespace_name, ROUND(((d.bytes - NVL(f.bytes, 0)) / d.bytes) * 100, 2) AS usage_pct, ROUND(d.bytes / 1024 / 1024 / 1024, 2) AS total_gb, ROUND(NVL(f.bytes, 0) / 1024 / 1024 / 1024, 2) AS free_gb FROM datafiles d LEFT JOIN free_space f ON f.tablespace_name = d.tablespace_name` : 'SELECT NULL AS tablespace_name, NULL AS usage_pct FROM dual';
if (error) {
  return [{ json: { ...req, execution_blocked: true, result_payload: { alert_id: req.alert_id, correlation_id: req.correlation_id, db: req.db, status: 'failed', sql_command: rawSql, message: error, sql_output: error } } }];
}
return [{ json: { ...req, execution_blocked: false, exec_sql: rawSql, post_usage_sql: postUsageSql } }];

const req = $('Validate Execute SQL').first().json;
if (req.execution_blocked) return [{ json: { result_payload: req.result_payload } }];
const execResult = $('Oracle - Execute Approved SQL').first().json || {};
const postRows = $input.all().map((item) => item.json);
function pick(row, ...keys) {
  for (const key of keys) {
    if (row[key] != null && row[key] !== '') return row[key];
    const upper = key.toUpperCase();
    const lower = key.toLowerCase();
    if (row[upper] != null && row[upper] !== '') return row[upper];
    if (row[lower] != null && row[lower] !== '') return row[lower];
  }
  return undefined;
}
const errorMessage = execResult.error?.message || execResult.message || execResult.description || '';
const failed = Boolean(execResult.error) || /ORA-\d+/i.test(String(errorMessage));
const usageRow = postRows[0] || {};
const afterUsagePct = pick(usageRow, 'usage_pct');
const payload = { alert_id: req.alert_id, correlation_id: req.correlation_id, db: req.db, status: failed ? 'failed' : 'completed', sql_command: req.exec_sql, message: failed ? String(errorMessage || 'Oracle SQL execution failed.') : 'SQL executed successfully.', sql_output: failed ? String(errorMessage || JSON.stringify(execResult)) : 'SQL executed successfully.', database_result: { after_usage_pct: afterUsagePct != null ? Number(afterUsagePct) : null, post_usage_rows: postRows, oracle_execute_result: execResult }, executed_by: req.requested_by };
return [{ json: { result_payload: payload } }];
